// Iterative factorial — accumulator loop.
int factorial(int n) {
    int result = 1;
    int i = 1;
    while (i <= n) {
        result = result * i;
        i = i + 1;
    }
    return result;
}

// Iterative Fibonacci — two-accumulator update.
int fib_iter(int n) {
    int a = 0;
    int b = 1;
    int i = 0;
    while (i < n) {
        int next = a + b;
        a = b;
        b = next;
        i = i + 1;
    }
    return a;
}

// Euclidean GCD — iterative, integer-only.
int gcd(int a, int b) {
    while (b != 0) {
        int t = b;
        b = a % b;
        a = t;
    }
    return a;
}

// Sum of 1..n via a for loop.
int triangle_num(int n) {
    int total = 0;
    for (int i = 1; i <= n; i++) {
        total = total + i;
    }
    return total;
}
